css: .accordion {
    @apply max-w-md mx-4 mt-4 border border-gray-400 rounded p-4;
}

.accordion button {
    @apply bg-gray-200 hover:bg-gray-400 text-gray-800 font-bold py-2 px-4 rounded;
}

.accordion-content {
    @apply hidden overflow-y-auto max-h-48;
}

button:focus {
    @apply outline-none;
}

button:active {
    @apply shadow-inner;
}
js: const accordionButtons = document.querySelectorAll('.accordion button');

accordionButtons.forEach(button => {
    button.addEventListener('click', event => {
        const accordionContent = document.getElementById(`accordion-content-${button.id.split('-')[1]}`);
        accordionContent.classList.toggle('hidden');
        button.classList.toggle('bg-gray-400');
        button.setAttribute('aria-expanded', accordionContent.classList.contains('hidden') ? 'false' : 'true');
    });
});
